```python
def merge_alternating(s1: str, s2: str) -> str:
    result = []
    for i in range(max(len(s1), len(s2))):
        if i < len(s1): result.append(s1[i])
        if i < len(s2): result.append(s2[i])
    return "".join(result)
```

