```python
def get_words_by_criteria(words, criteria=None):
    vowels = "aeiouAEIOU"
    if criteria == "continuous":
        return [w for w in words if w.lower().endswith("ing")]
    elif criteria == "vowel_rich":
        return [w for w in words if sum(1 for c in w if c in vowels) > 5]
    elif criteria == "consonant_rich":
        return [w for w in words if sum(1 for c in w if c.isalpha() and c not in vowels)
             > 5]
    elif criteria == "sorted":
        return [w for w in words if list(w.lower()) == sorted(w.lower())]
    return None
```

