def find_pairs_with_sum(lst: list, target: int) -> list:
    seen = set()
    pairs = set()
    for x in lst:
        comp = target - x
        if comp in seen:
            pairs.add((min(x, comp), max(x, comp)))
        seen.add(x)
    return list(pairs)
