def caesar_encrypt(s: str, k: int) -> str:
    result = []
    for c in s:
        if c.islower():
            result.append(chr((ord(c) - ord('a') + k) % 26 + ord('a')))
        else:
            result.append(c)
    return ''.join(result)
```

