n = int(input())
for _ in range(n):
    s = input().strip()
    stack = []
    valid = True
    match = {")":"(", "]":"[", "}":"{"}
    for ch in s:
        if ch in "([{":
            stack.append(ch)
        elif ch in ")]}":
            if not stack or stack[-1] != match[ch]:
                valid = False
                break
            stack.pop()
    if stack: valid = False
    print("VALID" if valid else "INVALID")
```

